import React, { useState, useEffect } from 'react';
import { YMaps, Map, Placemark } from '@pbe/react-yandex-maps';
import axios from 'axios';

function TestHome() {
  const [center, setCenter] = useState([55.751574, 37.573856]);
  const [markers, setMarkers] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selectedMarker, setSelectedMarker] = useState(null);

  // Загрузка маркеров из БД
  useEffect(() => {
    fetchMarkersFromDatabase();
  }, []);

  const fetchMarkersFromDatabase = async () => {
    try {
      setLoading(true);

      // В реальном приложении здесь будет запрос к вашему API
      // const response = await axios.get('/api/markers');

      // Демо-данные с изображениями
      const demoData = {
            items: [
                {
                id: 1,
                latitude: 55.751574,
                longitude: 37.573856,
                title: "Московский Кремль",
                description: "Исторический комплекс в центре Москвы",
                imageUrl: "https://upload.wikimedia.org/wikipedia/commons/thumb/5/5a/Moscow_Kremlin_from_Across_Moskva_River.jpg/800px-Moscow_Kremlin_from_Across_Moskva_River.jpg",
                type: "historic",
                address: "Москва, Кремль",
                rating: 4.8,
                category: "Достопримечательность"
                },
                {
                id: 2,
                latitude: 59.934280,
                longitude: 30.335098,
                title: "Эрмитаж",
                description: "Крупнейший художественный музей России",
                imageUrl: "https://upload.wikimedia.org/wikipedia/commons/thumb/d/dd/Winter_Palace_Panorama_3.jpg/800px-Winter_Palace_Panorama_3.jpg",
                type: "museum",
                address: "Санкт-Петербург, Дворцовая площадь, 2",
                rating: 4.9,
                category: "Музей"
                },
                {
                id: 3,
                latitude: 56.326887,
                longitude: 44.005986,
                title: "Нижегородский Кремль",
                description: "Крепость в историческом центре Нижнего Новгорода",
                imageUrl: "https://upload.wikimedia.org/wikipedia/commons/thumb/7/74/Nizhny_Novgorod_Kremlin_%283%29.JPG/800px-Nizhny_Novgorod_Kremlin_%283%29.JPG",
                type: "historic",
                address: "Нижний Новгород, Кремль",
                rating: 4.7,
                category: "Архитектура"
                },
                {
                id: 4,
                latitude: 55.7343,
                longitude: 37.6192,
                title: "Москва-Сити",
                description: "Московский международный деловой центр",
                imageUrl: "https://upload.wikimedia.org/wikipedia/commons/thumb/5/5c/Moscow_International_Business_Center_%2832342281702%29.jpg/800px-Moscow_International_Business_Center_%2832342281702%29.jpg",
                type: "modern",
                address: "Москва, Пресненская набережная",
                rating: 4.6,
                category: "Небоскребы"
                },
                {
                id: 5,
                latitude: 59.9398,
                longitude: 30.3146,
                title: "Исаакиевский собор",
                description: "Крупнейший православный храм Санкт-Петербурга",
                imageUrl: "https://upload.wikimedia.org/wikipedia/commons/thumb/7/78/St._Isaac%27s_Cathedral%2C_Saint_Petersburg.jpg/800px-St._Isaac%27s_Cathedral%2C_Saint_Petersburg.jpg",
                type: "religious",
                address: "Санкт-Петербург, Исаакиевская площадь, 4",
                rating: 4.8,
                category: "Собор"
                }
            ]
        };
      const demoData2 = {
        items: [
            {
            crossroads: {
                latitude: 45,
                longitude: 45,
                roads_sings: {
                    name_road: "Кутузовский проспект",
                    number_road: "D15",
                    sings: {
                        image: "images.jpg",
                        latitude: 25,
                        longitude: 25,
                        name_sing: "Главная дорога",
                        sing_id: 1
                    }
                },
                type_crossroad: "Т-образный перекресток"
            },
            id: 1,
            latitude: 56,
            longitude: 56,
            name_locality: "Москва"
            }
        ]
      }
    setMarkers(demoData2.items);

    if (demoData2.items.length > 0) {
      setCenter([demoData2.items[0].crossroads.roads_sings.sings.latitude, demoData2.items[0].crossroads.roads_sings.sings.longitude]);
    }

  } catch (error) {
    console.error('Ошибка загрузки маркеров:', error);
    setMarkers(getDefaultMarkers().items); // тоже исправьте на .items
  } finally {
    setLoading(false);
  }
  };

  // Функция для генерации HTML балуна с изображением
  const generateBalloonContent = (marker) => {
    return `
      <div style="
        max-width: 400px; 
        font-family: Arial, sans-serif;
        background: white;
        border-radius: 12px;
        overflow: hidden;
        box-shadow: 0 5px 20px rgba(0,0,0,0.15);
      ">
        <!-- Изображение -->
        <div style="position: relative; height: 200px; overflow: hidden;">
          <img 
            src="${marker.crossroads[0].roads_sings[0].sings[0].sings.image}" 
            style="
              width: 100%;
              height: 100%;
              object-fit: cover;
              transition: transform 0.3s;
            "
            onmouseover="this.style.transform='scale(1.05)'"
            onmouseout="this.style.transform='scale(1)'"
          />
        </div>

        <!-- Информация -->
        <div style="padding: 20px;">
          <h3 style="
            margin: 0 0 10px 0;
            color: #333;
            font-size: 20px;
            font-weight: 600;
          ">
            ${marker.crossroads[0].roads_sings[0].sings[0].name_sing}
          </h3>

          <!-- Координаты и адрес -->
          <div style="
            background: #f8f9fa;
            padding: 15px;
            border-radius: 8px;
            margin-bottom: 15px;
          ">
            <div style="
              display: grid;
              grid-template-columns: 1fr 1fr;
              gap: 10px;
              margin-bottom: 10px;
            ">
              <div>
                <div style="
                  font-size: 11px;
                  color: #888;
                  margin-bottom: 4px;
                ">
                  Широта
                </div>
                <div style="
                  font-family: 'Courier New', monospace;
                  font-size: 13px;
                  color: #333;
                  font-weight: bold;
                ">
                  ${marker.crossroads[0].roads_sings[0].sings[0].latitude}
                </div>
              </div>
              <div>
                <div style="
                  font-size: 11px;
                  color: #888;
                  margin-bottom: 4px;
                ">
                  Долгота
                </div>
                <div style="
                  font-family: 'Courier New', monospace;
                  font-size: 13px;
                  color: #333;
                  font-weight: bold;
                ">
                  ${marker.crossroads[0].roads_sings[0].sings[0].longitude}
                </div>
              </div>
            </div>

            <div>
              <div style="
                font-size: 11px;
                color: #888;
                margin-bottom: 4px;
              ">
                Адрес
              </div>
              <div style="
                font-size: 13px;
                color: #333;
              ">
                ${marker.name_locality}
              </div>
            </div>
          </div>
        </div>
      </div>
    `;
  };

  if (loading) {
    return (
      <div style={{ 
        display: 'flex', 
        justifyContent: 'center', 
        alignItems: 'center', 
        height: '600px',
        flexDirection: 'column',
        gap: '20px'
      }}>
        <div style={{
          width: '50px',
          height: '50px',
          border: '5px solid #f3f3f3',
          borderTop: '5px solid #3498db',
          borderRadius: '50%',
          animation: 'spin 1s linear infinite'
        }}></div>
        <style>{`
          @keyframes spin {
            0% { transform: rotate(0deg); }
            100% { transform: rotate(360deg); }
          }
        `}</style>
        <div>Загрузка карты и маркеров...</div>
      </div>
    );
  }

  return (
    <div style={{ 
      width: '100%', 
      maxWidth: '1200px', 
      margin: '0 auto',
      padding: '20px'
    }}>
      <h1 style={{ marginBottom: '20px', color: '#333' }}>
        Карта достопримечательностей
        <span style={{
          fontSize: '14px',
          color: '#666',
          marginLeft: '10px',
          backgroundColor: '#f0f0f0',
          padding: '4px 10px',
          borderRadius: '20px'
        }}>
          {markers.length} мест
        </span>
      </h1>

      <div style={{ 
        width: '100%', 
        height: '600px',
        borderRadius: '12px',
        overflow: 'hidden',
        boxShadow: '0 4px 20px rgba(0,0,0,0.1)',
        marginBottom: '20px'
      }}>
        <YMaps>
          <Map 
            state={{ center, zoom: 10 }} 
            width="100%" 
            height="100%"
            modules={['geoObject.addon.balloon', 'geoObject.addon.hint']}
          >
            {markers.map((marker) => (
              <Placemark
                key={marker.id}
                geometry={[marker.latitude, marker.longitude]}
                options={{
                  iconLayout: 'default#image',
                  iconImageSize: [48, 48],
                  iconImageOffset: [-24, -48],
                  hideIconOnBalloonOpen: false,
                  openBalloonOnClick: true,
                }}
                properties={{
                  hintContent: `<div style="padding: 5px 10px; font-weight: bold;">${marker.title}</div>`,
                  balloonContent: generateBalloonContent(marker),
                  balloonContentHeader: `<div style="padding: 10px; background: ${marker.color}; color: white; font-weight: bold; border-radius: 8px 8px 0 0;">${marker.title}</div>`,
                }}
                modules={['geoObject.addon.balloon']}
                onClick={() => {
                  setSelectedMarker(marker);
                  console.log('Выбран маркер:', marker.title);
                }}
              />
            ))}
          </Map>
        </YMaps>
      </div>
    </div>
  );
}

